class Solution:
    def mergeLogs(self, paths, responseTimes):
        # 获取日志总数
        n = len(paths)

        # 用于存储最终答案
        ans = []

        # i 表示当前正在处理的分组起点
        i = 0

        # 线性扫描整个数组
        while i < n:
            # 当前组的起始下标
            start = i

            # 当前组的请求路径
            current_path = paths[i]

            # 当前组内元素个数
            count = 0

            # 当前组内响应时间总和
            total = 0

            # 向后扩展当前组，直到路径发生变化
            while i < n and paths[i] == current_path:
                count += 1
                total += responseTimes[i]
                i += 1

            # 计算当前组平均响应时间，题目要求向下取整
            avg = total // count

            # 将当前组统计结果加入答案
            ans.append([start, count, avg])

        # 返回所有分组结果
        return ans
````

```java
import java.util.ArrayList;
import java.util.List;

class Solution {
    public int[][] mergeLogs(String[] paths, int[] responseTimes) {
        // 日志总数
        int n = paths.length;

        // 先用动态数组存储每一组结果，最后再转成二维数组返回
        List<int[]> list = new ArrayList<>();

        // i 表示当前处理到的位置
        int i = 0;

        // 线性扫描整个数组
        while (i < n) {
            // 当前组起始下标
            int start = i;

            // 当前组的请求路径
            String currentPath = paths[i];

            // 当前组连续出现次数
            int count = 0;

            // 当前组响应时间总和
            int total = 0;

            // 继续向后扫描，直到路径不同为止
            while (i < n && paths[i].equals(currentPath)) {
                count++;
                total += responseTimes[i];
                i++;
            }

            // 平均响应时间，向下取整
            int avg = total / count;

            // 保存当前组结果
            list.add(new int[] {start, count, avg});
        }

        // 将动态数组转换为题目要求的二维数组
        int[][] ans = new int[list.size()][3];
        for (int k = 0; k < list.size(); k++) {
            ans[k] = list.get(k);
        }

        return ans;
    }
}
