#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<vector<int>> mergeLogs(vector<string>& paths, vector<int>& responseTimes) {
        // 日志总数
        int n = (int)paths.size();

        // 存储最终答案
        vector<vector<int>> ans;

        // i 表示当前处理到的位置
        int i = 0;

        // 线性扫描整个数组
        while (i < n) {
            // 当前组起始下标
            int start = i;

            // 当前组的请求路径
            string currentPath = paths[i];

            // 当前组连续出现次数
            int count = 0;

            // 当前组响应时间总和
            int total = 0;

            // 向后扩展当前组，直到路径不同为止
            while (i < n && paths[i] == currentPath) {
                count++;
                total += responseTimes[i];
                i++;
            }

            // 计算平均响应时间，整数除法天然向下取整
            int avg = total / count;

            // 保存当前组结果
            ans.push_back({start, count, avg});
        }

        return ans;
    }
};
